  );
}

export function ActionPanel({
  actions,
  dropdownOpen,
  dropdownActions,
  onDropdownClose,
  contextLabel,
}: ActionPanelProps) {
  const actionsTriggerRef = useRef<HTMLButtonElement>(null);
  const primary = actions[0];
  if (!primary) return null;

  const actionsButton = actions.find(a => a.label === 'Actions');

