@use '../../styles/tokens' as *;

.action-panel {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: $action-panel-height;
  padding: 0 $space-2;
  border-top: 1px solid $color-border;
  background-color: rgba(255, 255, 255, 0.05);
  border-radius: 0 0 $radius-window $radius-window;
  flex-shrink: 0;
  animation: action-panel-slide-up $transition-slow ease-out both;
  animation-delay: $transition-fast;

  &__left {
    display: flex;
    align-items: center;
    gap: $space-2;
  }

  &__logo {
    flex-shrink: 0;
    opacity: 0.6;
  }

  &__context {
    font-family: $font-family;
    font-size: $font-sm;
    color: rgba($color-text-primary, 0.6);
    white-space: nowrap;
    line-height: 1;
  }

  &__right {
    display: flex;
    align-items: center;
    gap: $space-2;
  }

  &__primary-action {
    display: flex;
    align-items: center;
    gap: $space-2;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    font-family: $font-family;
    line-height: 1;
    transition: color $transition-fast ease;

    &:hover {
      .action-panel__primary-label {
        color: $color-text-primary;
      }
    }

    &:focus-visible {
      outline: 2px solid $color-accent;
      outline-offset: 2px;
      border-radius: $radius-sm;
    }
  }

  &__primary-label {
    font-size: $font-xs;
    font-weight: $font-weight-semibold;
    color: $color-text-primary;
    white-space: nowrap;
  }

  &__separator {
    width: 2px;
    height: 12px;
    background-color: rgba($color-text-primary, 0.1);
    flex-shrink: 0;
  }

  &__actions-trigger {
    display: flex;
    align-items: center;
    gap: $space-2;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    font-family: $font-family;
    line-height: 1;
    transition: color $transition-fast ease;

    &:hover {
